descriptor.templateCss:
:root{--g:#00e676;--a:#ffb300;--r:#ff5252;--b:#3b82f6;--p:#a78bfa;--bg:#0d1117;--card:#0f172a;--border:rgba(255,255,255,.07)}
.cw{width:100%;height:100%;background:var(--bg);border-radius:12px;display:flex;flex-direction:column;gap:7px;padding:8px;box-sizing:border-box;font-family:'Segoe UI',sans-serif;overflow:hidden}
/* HEADER */
.cw-hdr{background:linear-gradient(90deg,#0f172a,#1e293b);border-radius:9px;display:flex;align-items:center;gap:12px;padding:7px 14px;border:1px solid var(--border);flex-shrink:0}
.cw-hdr-l{display:flex;align-items:center;gap:10px;flex:1;min-width:0}
.cw-pulse{width:11px;height:11px;border-radius:50%;background:#334155;flex-shrink:0;transition:all .4s}
.cw-logo{width:34px;height:34px;background:rgba(59,130,246,.15);border:1.5px solid rgba(59,130,246,.4);border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:8px;font-weight:800;color:var(--b);letter-spacing:.05em;flex-shrink:0}
.cw-mname{font-size:13px;font-weight:800;color:#fff;white-space:nowrap}
.cw-msub{font-size:10px;color:rgba(255,255,255,.38)}
.cw-state-pill{font-size:11px;font-weight:700;padding:4px 14px;border-radius:20px;border:1.5px solid #334155;color:#94a3b8;text-transform:uppercase;letter-spacing:.07em;transition:all .4s;white-space:nowrap}
.cw-hdr-r{display:flex;align-items:center;gap:14px;flex-shrink:0}
.cw-hstat{display:flex;align-items:baseline;gap:2px}
.cw-hv{font-size:17px;font-weight:800}
.cw-hu{font-size:9px;color:rgba(255,255,255,.4)}
.cw-clock{font-size:11px;color:rgba(255,255,255,.3);font-family:monospace}
/* NAV TABS */
.cw-nav{display:flex;align-items:center;gap:4px;background:#0f172a;border-radius:8px;padding:4px 6px;flex-shrink:0;border:1px solid var(--border)}
.cw-navbtn{background:transparent;border:none;color:rgba(255,255,255,.45);font-size:12px;font-weight:600;padding:6px 14px;border-radius:6px;cursor:pointer;transition:all .2s;letter-spacing:.02em;white-space:nowrap}
.cw-navbtn.active,.cw-navbtn:active{background:rgba(59,130,246,.18);color:#fff;border-bottom:2px solid var(--b)}
.cw-navbtn:hover:not(.active){background:rgba(255,255,255,.06);color:rgba(255,255,255,.7)}
.cw-nav-spacer{flex:1}
.cw-nav-info{font-size:10px;color:rgba(255,255,255,.25);white-space:nowrap}
/* PANELS */
.cw-panel{flex:1;display:none;flex-direction:column;gap:7px;min-height:0;overflow:hidden}
.cw-panel[ng-show]{display:flex}
/* KPI ROW */
.cw-kpi-row{display:grid;grid-template-columns:repeat(6,1fr);gap:6px;flex-shrink:0}
.cw-kpi{background:var(--card);border-radius:8px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:8px 4px;position:relative;overflow:hidden;border-top:2px solid #334155;transition:border-top-color .4s;min-height:68px}
.cw-ki{font-size:16px;margin-bottom:3px}
.cw-kv{font-size:clamp(14px,2vw,24px);font-weight:800;color:#fff;line-height:1;transition:color .4s}
.cw-ku{font-size:8px;color:rgba(255,255,255,.35);margin-top:1px}
.cw-kl{font-size:8px;color:rgba(255,255,255,.45);margin-top:4px;text-transform:uppercase;letter-spacing:.06em;text-align:center}
.cw-kbar{position:absolute;bottom:0;left:0;height:2px;background:#334155;transition:width .6s ease,background .4s;border-radius:2px}
/* GAUGES */
.cw-gauges{display:grid;grid-template-columns:repeat(4,1fr);gap:6px;flex-shrink:0}
.cw-gc{background:var(--card);border-radius:8px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:6px}
.cw-gsvg{width:100%;max-width:140px}
.cw-gz{font-size:9px;font-weight:700;padding:2px 10px;border-radius:20px;margin-top:2px;letter-spacing:.05em;text-transform:uppercase;background:rgba(51,65,85,.5);color:#64748b;transition:all .4s;white-space:nowrap}
/* BOTTOM */
.cw-bottom{display:grid;grid-template-columns:1fr 2fr;gap:6px;flex:1;min-height:0}
.cw-sbox,.cw-pbox{background:var(--card);border-radius:8px;padding:10px 12px;display:flex;flex-direction:column;gap:5px;overflow:hidden}
.cw-boxtitle,.alm-boxtitle{font-size:9px;color:rgba(255,255,255,.35);text-transform:uppercase;letter-spacing:.07em;margin-bottom:3px;flex-shrink:0}
.cw-srow{display:flex;align-items:center;gap:7px}
.cw-dot{width:7px;height:7px;border-radius:50%;background:#334155;flex-shrink:0;transition:all .3s}
.cw-sk{font-size:11px;color:rgba(255,255,255,.55);flex:1}
.cw-sv{font-size:11px;font-weight:700;color:#94a3b8;transition:color .3s}
.cw-pmain{display:flex;align-items:baseline;gap:6px}
.cw-pnum{font-size:34px;font-weight:800;color:#fff;transition:color .4s}
.cw-psep{font-size:20px;color:rgba(255,255,255,.2)}
.cw-ptgt{font-size:20px;font-weight:600;color:rgba(255,255,255,.4)}
.cw-psub{font-size:9px;color:rgba(255,255,255,.3);text-transform:uppercase;letter-spacing:.06em}
.cw-bwrap{width:100%;height:5px;background:#1e293b;border-radius:5px;overflow:hidden;margin:5px 0;flex-shrink:0}
.cw-bfill{height:100%;width:0;background:#334155;border-radius:5px;transition:width .7s ease,background .4s}
.cw-patt{font-size:12px;font-weight:700;color:#64748b;transition:color .4s}
.cw-prow{display:flex;gap:14px;margin-top:4px}
.cw-pst{display:flex;align-items:baseline;gap:3px}
.cw-psv{font-size:15px;font-weight:800}
.cw-psl{font-size:9px;color:rgba(255,255,255,.4)}
/* OEE TAB */
.oee-top{display:grid;grid-template-columns:1fr 2fr;gap:7px;flex-shrink:0}
.oee-big-card{background:var(--card);border-radius:9px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:16px;border:1px solid var(--border)}
.oee-big-label{font-size:10px;color:rgba(255,255,255,.35);text-transform:uppercase;letter-spacing:.07em;margin-bottom:8px}
.oee-big-num{font-size:52px;font-weight:900;color:#fff;line-height:1;transition:color .4s}
.oee-big-zone{font-size:11px;font-weight:700;padding:3px 14px;border-radius:20px;margin-top:10px;text-transform:uppercase;letter-spacing:.06em;background:rgba(51,65,85,.5);color:#64748b;transition:all .4s}
.oee-mini-grid{display:grid;grid-template-columns:1fr 1fr;gap:6px}
.oee-mini{background:var(--card);border-radius:8px;padding:10px 12px;border:1px solid var(--border)}
.oee-ml{font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.07em;margin-bottom:4px}
.oee-mv{font-size:26px;font-weight:800;color:#fff;transition:color .4s;margin-bottom:6px}
.oee-mbar{width:100%;height:4px;background:#1e293b;border-radius:4px;overflow:hidden}
.oee-mfill{height:100%;width:0;border-radius:4px;transition:width .7s ease,background .4s}
/* SHIFT TABLE */
.shift-grid{display:grid;grid-template-columns:auto repeat(3,1fr);gap:4px 8px;background:var(--card);border-radius:8px;padding:10px 14px;flex:1;min-height:0;align-content:start}
.shift-hdr{font-size:10px;font-weight:700;color:rgba(255,255,255,.5);text-align:center;text-transform:uppercase;letter-spacing:.07em;padding:4px 0;border-bottom:1px solid rgba(255,255,255,.08)}
.shift-lbl{font-size:11px;color:rgba(255,255,255,.55);padding:5px 0;border-bottom:1px solid rgba(255,255,255,.04)}
.shift-val{font-size:12px;font-weight:700;color:#94a3b8;text-align:center;padding:5px 0;border-bottom:1px solid rgba(255,255,255,.04);transition:color .3s}
/* PRODUCTION TAB */
.prod-top{display:grid;grid-template-columns:1fr 1fr;gap:7px;flex-shrink:0}
.prod-hero{background:var(--card);border-radius:9px;display:flex;flex-direction:column;align-items:flex-start;justify-content:center;padding:16px;border:1px solid var(--border)}
.prod-hero-lbl{font-size:10px;color:rgba(255,255,255,.35);text-transform:uppercase;letter-spacing:.07em;margin-bottom:6px}
.prod-hero-num{font-size:52px;font-weight:900;color:#fff;line-height:1;transition:color .4s}
.prod-hero-sub{font-size:12px;color:rgba(255,255,255,.4);margin-top:4px}
.prod-bwrap{width:100%;height:6px;background:#1e293b;border-radius:6px;overflow:hidden;margin:8px 0}
.prod-bfill{height:100%;width:0;background:#334155;border-radius:6px;transition:width .7s,background .4s}
.prod-att{font-size:13px;font-weight:700;color:#64748b;transition:color .4s}
.prod-stats-grid{display:grid;grid-template-columns:1fr 1fr;gap:6px}
.prod-stat-card{background:var(--card);border-radius:8px;padding:12px 14px;border:1px solid var(--border);border-top:2px solid #334155;transition:border-top-color .4s}
.psc-l{font-size:9px;color:rgba(255,255,255,.35);text-transform:uppercase;letter-spacing:.07em;margin-bottom:6px}
.psc-v{font-size:28px;font-weight:800;transition:color .4s}
/* ALARMS TAB */
.alm-top{display:grid;grid-template-columns:1fr 1fr;gap:7px;flex-shrink:0}
.alm-big{background:var(--card);border-radius:9px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:14px;border:1px solid var(--border);transition:border-color .4s}
.alm-big-icon{font-size:36px;margin-bottom:8px}
.alm-big-txt{font-size:22px;font-weight:800;color:#fff;transition:color .4s}
.alm-big-sub{font-size:10px;color:rgba(255,255,255,.35);margin-top:4px;text-transform:uppercase;letter-spacing:.07em}
.alm-params{background:var(--card);border-radius:9px;padding:12px 14px;border:1px solid var(--border);display:flex;flex-direction:column;gap:8px}
.alm-param{display:flex;align-items:center;justify-content:space-between}
.ap-l{font-size:11px;color:rgba(255,255,255,.5)}
.ap-v{font-size:16px;font-weight:700;color:#fff}
.alm-status-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:6px;flex:1;min-height:0;align-content:start}
.alm-scard{background:var(--card);border-radius:8px;padding:10px 12px;display:flex;align-items:center;gap:8px;border:1px solid var(--border)}
.asc-dot{width:8px;height:8px;border-radius:50%;background:#334155;flex-shrink:0;transition:all .3s}
.asc-l{font-size:11px;color:rgba(255,255,255,.5);flex:1}
.asc-v{font-size:12px;font-weight:700;color:#94a3b8;transition:color .3s}

descriptor.controllerScript:
var ctx, timer;
var SC = {'RUNNING':'#00e676','running':'#00e676','1':'#00e676','STOPPED':'#ff5252','stopped':'#ff5252','0':'#ff5252','IDLE':'#ffb300','idle':'#ffb300','ALARM':'#ff1744','alarm':'#ff1744','FAULT':'#ff1744','fault':'#ff1744'};
var KM = [1,3000,500,900,120,1];

function el(id){return ctx.$container[0].querySelector('#'+id);}
function set(id,txt){var e=el(id);if(e)e.textContent=String(txt);}
function sty(id,p,v){var e=el(id);if(e)e.style[p]=v;}
function p2(n){return String(n).padStart(2,'0');}
function oc(n){return n>=75?'#00e676':n>=50?'#ffb300':'#ff5252';}
function oz(n){return n>=75?'WORLD CLASS':n>=50?'IMPROVING':'ACTION NEEDED';}
function bon(v){return parseFloat(v)>0||v===true||v==='true'||v==='1'||v==='RUNNING'||v==='ON';}
function fmt(v,d){var n=parseFloat(v);return isNaN(n)?'--':(d===0?Math.round(n).toString():n.toFixed(d===undefined?1:d));}

function arcPath(pct){
  var r=55,cx=70,cy=95,sA=-220*Math.PI/180,sw=280*Math.PI/180;
  var eA=sA+(Math.min(pct,99.9)/100)*sw;
  return 'M '+(cx+r*Math.cos(sA)).toFixed(2)+' '+(cy+r*Math.sin(sA)).toFixed(2)+' A '+r+' '+r+' 0 '+(pct>=50?1:0)+' 1 '+(cx+r*Math.cos(eA)).toFixed(2)+' '+(cy+r*Math.sin(eA)).toFixed(2);
}
function gauge(i,val){
  var arc=el('ga-'+i),pt=el('gp-'+i),gz=el('gz-'+i);
  if(!arc||!pt||!gz)return;
  var n=parseFloat(val);
  if(isNaN(n)){arc.setAttribute('stroke','#334155');pt.textContent='--%';gz.textContent='NO DATA';gz.style.background='rgba(51,65,85,.4)';gz.style.color='#64748b';gz.style.border='none';return;}
  n=Math.max(0,Math.min(100,n));
  var c=oc(n);
  arc.setAttribute('d',arcPath(n));arc.setAttribute('stroke',c);
  pt.textContent=n.toFixed(1)+'%';pt.setAttribute('fill',c);
  gz.textContent=oz(n);gz.style.background=c+'22';gz.style.color=c;gz.style.border='1px solid '+c+'55';
}
function kpi(i,raw,isStr,isAlm){
  var kp=el('kpi-'+i),kv=el('kv-'+i),kb=el('kb-'+i);if(!kp||!kv||!kb)return;
  var c='#334155',p=0,d='--';
  if(raw!==undefined&&raw!==null){
    if(isAlm){var on=bon(raw);d=on?'ACTIVE':'OK';c=on?'#ff1744':'#00e676';p=on?100:5;}
    else if(isStr){var s=String(raw).toUpperCase().slice(0,8);d=s;c=SC[String(raw)]||SC[s]||'#3b82f6';p=c==='#00e676'?100:c==='#ffb300'?50:20;}
    else{var n=parseFloat(raw);if(!isNaN(n)){d=n>=100?Math.round(n).toString():n>=10?n.toFixed(1):n.toFixed(2);p=Math.min(100,(n/KM[i])*100);c=[null,'#00e676','#ffb300','#3b82f6','#a78bfa'][i]||oc(p);}}
  }
  kv.textContent=d;kv.style.color=c;kp.style.borderTopColor=c;kb.style.width=p+'%';kb.style.background=c;
}
function statusRow(i,raw,onLbl,offLbl,onC,offC){
  var dot=el('d-'+i),sv=el('sv-'+i);if(!dot||!sv)return;
  if(raw===undefined||raw===null)return;
  var on=bon(raw),c=on?onC:offC;
  dot.style.background=c;dot.style.boxShadow='0 0 7px '+c+'88';sv.textContent=on?onLbl:offLbl;sv.style.color=c;
}
function ascRow(i,raw,onLbl,offLbl,onC,offC){
  var dot=el('asc-d'+i),sv=el('asc-v'+i);if(!dot||!sv)return;
  if(raw===undefined||raw===null)return;
  var on=bon(raw),c=on?onC:offC;
  dot.style.background=c;dot.style.boxShadow='0 0 6px '+c+'77';sv.textContent=on?onLbl:offLbl;sv.style.color=c;
}
function colorVal(id,val,invert){
  var n=parseFloat(val);if(isNaN(n))return;
  var c=oc(invert?(100-n):n);
  set(id,n.toFixed(1)+'%');sty(id,'color',c);
}
function miniBar(i,val,col){
  var mv=el('omv-'+i),mf=el('omf-'+i);if(!mv||!mf)return;
  var n=parseFloat(val);if(isNaN(n))return;
  n=Math.max(0,Math.min(100,n));
  var c=col||oc(n);
  mv.textContent=n.toFixed(1)+'%';mv.style.color=c;
  mf.style.width=n+'%';mf.style.background=c;
}

self.onInit=function(){
  ctx=self.ctx;
  ctx.$scope.tab='rt';
  timer=setInterval(function(){var d=new Date();set('cw-clock',p2(d.getHours())+':'+p2(d.getMinutes())+':'+p2(d.getSeconds()));},1000);
};

self.onDataUpdated=function(){
  try{
    var v={};
    for(var i=0;i<ctx.data.length;i++){var d=ctx.data[i];if(d&&d.dataKey&&d.data&&d.data.length)v[d.dataKey.name]=d.data[d.data.length-1][1];}
    var now=new Date();set('cw-upd',p2(now.getHours())+':'+p2(now.getMinutes())+':'+p2(now.getSeconds()));

    // HEADER
    var state=String(v.machine_state||'UNKNOWN'),sc=SC[state]||SC[state.toUpperCase()]||'#3b82f6';
    var pulse=el('cw-pulse'),pill=el('cw-state-pill');
    if(pulse){pulse.style.background=sc;pulse.style.boxShadow='0 0 14px '+sc+'99';}
    if(pill){pill.textContent=state.toUpperCase().slice(0,12);pill.style.color=sc;pill.style.borderColor=sc+'66';}
    set('h-spindle',v.spindle_speed?Math.round(parseFloat(v.spindle_speed)):'--');
    set('h-parts',  v.part_count   ?Math.round(parseFloat(v.part_count))   :'--');
    set('h-pgm',    v.program_no||'--');

    // RT - KPIs
    kpi(0,v.machine_state,true,false);kpi(1,v.spindle_speed,false,false);
    kpi(2,v.feed_rate,false,false);   kpi(3,v.part_count,false,false);
    kpi(4,v.last_cycle_time_sec,false,false);kpi(5,v.alarm_active,false,true);

    // RT - Gauges
    gauge(0,v.oee_today);gauge(1,v.availability_today);gauge(2,v.performance_today);gauge(3,v.quality_today);

    // RT - Status
    statusRow(0,v.is_running,       'RUNNING','STOPPED','#00e676','#ff5252');
    statusRow(1,v.auto_mode,        'ON',     'OFF',    '#3b82f6','#64748b');
    statusRow(2,v.motion_status,    'YES',    'NO',     '#ffb300','#64748b');
    statusRow(3,v.alarm_active,     'ACTIVE', 'OK',     '#ff1744','#00e676');
    statusRow(4,v.emergency,        'ACTIVE', 'CLEAR',  '#ff1744','#00e676');
    statusRow(5,v.connection_status,'OK',     'OFFLINE','#00e676','#ff5252');

    // RT - Production
    var pts=parseFloat(v.parts_today||v.part_count||0)||0,tgt=parseFloat(v.target_today||0)||0;
    var pct=tgt>0?Math.min(100,(pts/tgt)*100):0,pc=oc(pct);
    set('rt-pnum',Math.round(pts));set('rt-ptgt',tgt>0?Math.round(tgt):'?');
    set('rt-att',pct.toFixed(1)+'% attainment');sty('rt-pnum','color',pc);sty('rt-att','color',pc);
    var pb=el('rt-prog');if(pb){pb.style.width=pct+'%';pb.style.background=pc;}
    set('rt-good',v.good_parts_today?Math.round(parseFloat(v.good_parts_today)):'--');
    set('rt-rej', v.rejections_today?Math.round(parseFloat(v.rejections_today)):'--');
    var dn=(parseFloat(v.downtime_min_shift_a||0)+parseFloat(v.downtime_min_shift_b||0)).toFixed(0);
    set('rt-dn',dn>0?dn:'--');

    // OEE TAB
    var oeeN=parseFloat(v.oee_today||0)||0;
    set('oee-big-num',oeeN.toFixed(1)+'%');sty('oee-big-num','color',oc(oeeN));
    var bz=el('oee-big-zone');if(bz){bz.textContent=oz(oeeN);bz.style.background=oc(oeeN)+'22';bz.style.color=oc(oeeN);bz.style.border='1px solid '+oc(oeeN)+'44';}
    miniBar(0,v.availability_today,'#3b82f6');
    miniBar(1,v.performance_today, '#ffb300');
    miniBar(2,v.quality_today,     '#a78bfa');
    miniBar(3,v.attainment_today,  '#00e676');
    // shift table for OEE
    var sFields=[['oee','sa-oee','sb-oee','st-oee'],['av','sa-av','sb-av','st-av'],['pf','sa-pf','sb-pf','st-pf'],['ql','sa-ql','sb-ql','st-ql']];
    var sKeys=[['oee_shift_a','oee_shift_b','oee_today'],['availability_shift_a','availability_shift_b','availability_today'],['performance_shift_a','performance_shift_b','performance_today'],['quality_shift_a','quality_shift_b','quality_today']];
    for(var si=0;si<sKeys.length;si++){
      for(var sj=0;sj<3;sj++){
        var sv2=parseFloat(v[sKeys[si][sj]]);
        var el2=el(sFields[si][sj+1]);
        if(el2){if(!isNaN(sv2)){el2.textContent=sv2.toFixed(1)+'%';el2.style.color=oc(sv2);}else{el2.textContent='--';el2.style.color='#64748b';}}
      }
    }
    [['sa-pc','sb-pc','st-pc','parts_shift_a','parts_shift_b','parts_today'],['sa-rm','sb-rm','st-rm','running_min_shift_a','running_min_shift_b',null],['sa-dt','sb-dt','st-dt','downtime_min_shift_a','downtime_min_shift_b',null],['sa-al','sb-al','st-al','alarms_shift_a','alarms_shift_b',null]].forEach(function(r){
      [0,1,2].forEach(function(j){var k2=r[3+j];var e2=el(r[j]);if(!e2)return;if(k2&&v[k2]!==undefined){var n2=parseFloat(v[k2]);e2.textContent=isNaN(n2)?v[k2]:Math.round(n2);}else if(j===2&&r[0]==='sa-pc'){var t=parseFloat(v.parts_today||0)||0;e2.textContent=Math.round(t);}});
    });

    // PRODUCTION TAB
    set('prod-num',Math.round(pts));sty('prod-num','color',pc);
    set('prod-tgt',tgt>0?Math.round(tgt):'?');
    set('prod-att',pct.toFixed(1)+'% attainment');sty('prod-att','color',pc);
    var pbp=el('prod-prog');if(pbp){pbp.style.width=pct+'%';pbp.style.background=pc;}
    var good2=parseFloat(v.good_parts_today||0)||0,rej2=parseFloat(v.rejections_today||0)||0;
    set('p-good',good2>0?Math.round(good2):'--');sty('p-good','color','#00e676');
    set('p-rej', rej2>0?Math.round(rej2): '--');sty('p-rej','color','#ff5252');
    var rr=pts>0&&rej2>0?((rej2/pts)*100).toFixed(1)+'%':'0%';
    set('p-rr',rr);
    var avgC=parseFloat(v.avg_cycle_shift_a||v.avg_cycle_shift_b||0)||0;
    set('p-cyc',avgC>0?avgC.toFixed(1):'--');
    // prod shift table
    [['pa-pc','pb-pc','pt-pc','parts_shift_a','parts_shift_b','parts_today'],['pa-tg','pb-tg','pt-tg','target_shift_a','target_shift_b','target_today'],['pa-gp','pb-gp','pt-gp','good_parts_shift_a','good_parts_shift_b','good_parts_today'],['pa-rj','pb-rj','pt-rj','rejections_shift_a','rejections_shift_b','rejections_today'],['pa-cy','pb-cy','pt-cy','avg_cycle_shift_a','avg_cycle_shift_b',null]].forEach(function(r){
      [0,1,2].forEach(function(j){var k3=r[3+j];var e3=el(r[j]);if(!e3)return;if(k3&&v[k3]!==undefined){var n3=parseFloat(v[k3]);e3.textContent=isNaN(n3)?'--':r[0]==='pa-cy'?n3.toFixed(1):Math.round(n3);}});
    });
    var atts=[['pa-at','parts_shift_a','target_shift_a'],['pb-at','parts_shift_b','target_shift_b'],['pt-at','parts_today','target_today']];
    atts.forEach(function(a){var e4=el(a[0]);if(!e4)return;var p4=parseFloat(v[a[1]]||0)||0,t4=parseFloat(v[a[2]]||0)||0;var at4=t4>0?Math.min(100,(p4/t4)*100):0;e4.textContent=at4.toFixed(1)+'%';e4.style.color=oc(at4);});

    // ALARMS TAB
    var almOn=bon(v.alarm_active);
    var abi=el('alm-icon'),abt=el('alm-txt'),abc=el('alm-big-card');
    if(abi)abi.textContent=almOn?'🔴':'🟢';
    if(abt){abt.textContent=almOn?'ALARM ACTIVE':'NORMAL';abt.style.color=almOn?'#ff1744':'#00e676';}
    if(abc){abc.style.borderColor=almOn?'#ff174466':'#00e67633';}
    set('ap-no',  v.alarm_no   ||'--');
    set('ap-idle',v.idle_time_sec?Math.round(parseFloat(v.idle_time_sec)):'--');
    set('ap-raw', v.raw_cycle_time_sec?parseFloat(v.raw_cycle_time_sec).toFixed(1):'--');
    set('ap-sp',  v.spindle_speed?Math.round(parseFloat(v.spindle_speed)):'--');
    set('ap-fr',  v.feed_rate?parseFloat(v.feed_rate).toFixed(1):'--');
    set('ap-pgm', v.program_no||'--');
    ascRow(0,v.is_running,       'RUNNING','STOPPED','#00e676','#ff5252');
    ascRow(1,v.auto_mode,        'ON',     'OFF',    '#3b82f6','#64748b');
    ascRow(2,v.motion_status,    'YES',    'NO',     '#ffb300','#64748b');
    ascRow(3,v.alarm_active,     'ACTIVE', 'OK',     '#ff1744','#00e676');
    ascRow(4,v.emergency,        'ACTIVE', 'CLEAR',  '#ff1744','#00e676');
    ascRow(5,v.run_status,       'RUNNING','IDLE',   '#00e676','#64748b');
    ascRow(6,v.connection_status,'OK',     'OFFLINE','#00e676','#ff5252');
    var dtA=parseFloat(v.downtime_min_shift_a||0)||0,dtB=parseFloat(v.downtime_min_shift_b||0)||0;
    var e7=el('asc-v7'),e8=el('asc-v8');
    if(e7){e7.textContent=(dtA>0?dtA.toFixed(0):'-')+' min';e7.style.color=dtA>30?'#ff5252':dtA>10?'#ffb300':'#00e676';}
    if(e8){e8.textContent=(dtB>0?dtB.toFixed(0):'-')+' min';e8.style.color=dtB>30?'#ff5252':dtB>10?'#ffb300':'#00e676';}
    var da=el('asc-d7'),db=el('asc-d8');
    if(da)da.style.background=dtA>30?'#ff5252':dtA>10?'#ffb300':'#00e676';
    if(db)db.style.background=dtB>30?'#ff5252':dtB>10?'#ffb300':'#00e676';

    ctx.detectChanges();
  }catch(e){console.error('[CNC]',e);}
};
self.onDestroy=function(){if(timer)clearInterval(timer);};
